 73→const sanitizeDoodlePayload = (payload) => {
 74→    const points = Array.isArray(payload?.points)
 75→        ? payload.points
 76→            .map((point) => Number(point))
 77→            .filter((point) => !Number.isNaN(point))
 78→            .map((point) => clamp(point, 0, 1))
 79→        : [];
