 99→const sanitizeStickerPayload = (payload) => {
100→    const sticker = typeof payload?.sticker === "string" ? payload.sticker.trim() : "";
101→    const stickerId = typeof payload?.stickerId === "string" ? payload.stickerId.trim() : "";
102→    if(!sticker && !stickerId){
