104→    }
105→
106→    const result = {
107→        x: normalizePosition(payload?.x, 0.5),
108→        y: normalizePosition(payload?.y, 0.5),
109→        scale: clamp(normalizeNumber(payload?.scale, 1), 0.25, 6),
110→        rotation: clamp(normalizeNumber(payload?.rotation, 0), -360, 360)
111→    };
112→
113→    if(sticker){
