160→const isPointerNearDoodle = (pointerX, pointerY, doodle, radiusPx = ERASER_RADIUS_PX) => {
161→    if(!doodle?.points || doodle.points.length < 4){
162→        return false;
163→    }
164→
165→    const strokeWidth = Math.max(1, Number(doodle.strokeWidth) || 3);
166→    const hitDistance = radiusPx + strokeWidth * 0.5;
167→
168→    const points = doodle.points;
169→    for(let i = 0; i < points.length - 2; i += 2){
170→        const dist = distancePointToSegment(
171→            pointerX,
172→            pointerY,
173→            points[i],
174→            points[i + 1],
175→            points[i + 2],
176→            points[i + 3]
177→        );
178→        if(dist <= hitDistance){
179→            return true;
180→        }
181→    }
182→
183→    return false;
184→};
