141→    }
142→
143→    const requestedFontFamily = typeof payload?.fontFamily === "string" ? payload.fontFamily.trim() : "";
144→    const requestedFontStyle = typeof payload?.fontStyle === "string" ? payload.fontStyle.trim().toLowerCase() : "";
145→
