161→const sanitizePayloadByType = (itemType, payload) => {
162→    if(!payload || typeof payload !== "object" || Array.isArray(payload)){
163→        throw {status: 400, error: "payload should be an object"};
164→    }
165→
166→    if(itemType === "doodle"){
167→        return sanitizeDoodlePayload(payload);
