182→const throwMappedDatabaseError = (error, fallbackErrorMessage) => {
183→    const code = String(error?.code || "");
184→    const message = error?.message || fallbackErrorMessage;
185→    const details = error?.details || "";
186→
187→    if(code === "23514"){
188→        throw {
189→            status: 400,
190→            error: `database check constraint rejected payload: ${message}${details ? ` (${details})` : ""}`
191→        };
192→    }
193→
194→    if(code === "22P02"){
195→        throw {status: 400, error: "invalid uuid or malformed value in request"};
196→    }
197→
198→    throw {status: 500, error: fallbackErrorMessage};
199→};
