299→export const getFreedomWallItemsService = async(weekId, limit, cursor, types) => {
300→    if(!weekId){
301→        throw {status: 400, error: "weekId is required"};
302→    }
303→
304→    const parsedLimit = parseLimit(limit);
305→    const typeFilters = parseTypeFilters(types);
306→
307→    let query = supabase
308→        .from("freedom_wall_items")
309→        .select(selectItemColumns)
310→        .eq("week_id", weekId)
311→        .is("deleted_at", null)
312→        .order("z_index", {ascending: true})
313→        .order("created_at", {ascending: true})
314→        .order("id", {ascending: true})
315→        .limit(parsedLimit + 1);
316→
317→    if(cursor){
318→        query = query.gt("created_at", cursor);
319→    }
320→
321→    if(typeFilters.length > 0){
322→        query = query.in("item_type", typeFilters);
323→    }
324→
325→    const {data: items, error: itemsError} = await query;
326→
327→    if(itemsError){
328→        console.error("supabase error while reading freedom wall items:", itemsError.message);
329→        throw {status: 500, error: "failed to fetch freedom wall items"};
330→    }
331→
332→    const hasMore = (items || []).length > parsedLimit;
333→    const slicedItems = hasMore ? items.slice(0, parsedLimit) : (items || []);
334→    const nextCursor = hasMore
335→        ? slicedItems[slicedItems.length - 1]?.created_at || null
336→        : null;
337→
338→    return {
339→        data: slicedItems,
340→        hasMore: hasMore,
341→        nextCursor: nextCursor
342→    };
343→};
