353→    const width = clamp((Number(payload?.width) || 0.26) * stageWidth, 110 * wallSizeScale, stageWidth * 0.9);
354→    const height = clamp((Number(payload?.height) || 0.2) * stageHeight, 60 * wallSizeScale, stageHeight * 0.8);
355→    const x = clamp((Number(payload?.x) || 0.45) * stageWidth, 0, Math.max(0, stageWidth - width));
356→    const y = clamp((Number(payload?.y) || 0.45) * stageHeight, 0, Math.max(0, stageHeight - height));
357→    const fontStyle = NOTE_STYLE_OPTIONS.includes(payload?.fontStyle) ? payload.fontStyle : "normal";
358→    const bgColor = payload?.bgColor || "#fff4a8";
359→    const curlSize = Math.min(width, height) * 0.14;
360→    const pinSize = Math.max(5, Math.min(width, height) * 0.04);
361→
362→    const borderStroke = isDraft ? "#a21caf" : isSelected ? "#a21caf" : "rgba(0,0,0,0.1)";
363→    const borderWidth = isDraft ? 2 : isSelected ? 2 : 0.5;
